import { Slider as SliderPrimitive, useSlider, useSliderContext } from '@ark-ui/react/slider';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, ReactElement, ReactNode } from 'react';
import { Children, cloneElement, forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Slider.module.css';

const SliderRoot = forwardRef<
  ComponentRef<typeof SliderPrimitive.Root>,
  ComponentProps<typeof SliderPrimitive.Root>
>(function SliderRoot({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Root
      ref={ref}
      data-slot="slider-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderRootProvider = forwardRef<
  ComponentRef<typeof SliderPrimitive.RootProvider>,
  ComponentProps<typeof SliderPrimitive.RootProvider>
>(function SliderRootProvider({ className, ...props }, ref) {
  return (
    <SliderPrimitive.RootProvider
      ref={ref}
      data-slot="slider-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderLabel = forwardRef<
  ComponentRef<typeof SliderPrimitive.Label>,
  ComponentProps<typeof SliderPrimitive.Label>
>(function SliderLabel({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Label
      ref={ref}
      data-slot="slider-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderValueText = forwardRef<
  ComponentRef<typeof SliderPrimitive.ValueText>,
  ComponentProps<typeof SliderPrimitive.ValueText>
>(function SliderValueText({ className, ...props }, ref) {
  return (
    <SliderPrimitive.ValueText
      ref={ref}
      data-slot="slider-value-text"
      className={clsx(styles.valueText, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderControl = forwardRef<
  ComponentRef<typeof SliderPrimitive.Control>,
  ComponentProps<typeof SliderPrimitive.Control>
>(function SliderControl({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Control
      ref={ref}
      data-slot="slider-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderTrack = forwardRef<
  ComponentRef<typeof SliderPrimitive.Track>,
  ComponentProps<typeof SliderPrimitive.Track>
>(function SliderTrack({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Track
      ref={ref}
      data-slot="slider-track"
      className={clsx(styles.track, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderRange = forwardRef<
  ComponentRef<typeof SliderPrimitive.Range>,
  ComponentProps<typeof SliderPrimitive.Range>
>(function SliderRange({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Range
      ref={ref}
      data-slot="slider-range"
      className={clsx(styles.range, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderThumb = forwardRef<
  ComponentRef<typeof SliderPrimitive.Thumb>,
  ComponentProps<typeof SliderPrimitive.Thumb>
>(function SliderThumb({ asChild, children, className, ...props }, ref) {
  return (
    <SliderPrimitive.Thumb
      ref={ref}
      asChild={asChild}
      data-slot="slider-thumb"
      className={clsx(styles.thumb, normalizeClassName(className))}
      {...props}
    >
      {withHiddenInput(children, asChild)}
    </SliderPrimitive.Thumb>
  );
});

function withHiddenInput(children: ReactNode, asChild?: boolean) {
  const hiddenInput = <SliderPrimitive.HiddenInput data-slot="slider-hidden-input" />;

  if (!asChild) {
    return (
      <>
        {children}
        {hiddenInput}
      </>
    );
  }

  const child = Children.only(children) as ReactElement<{ children?: ReactNode }>;

  return cloneElement(child, {}, child.props.children, hiddenInput);
}

function SliderThumbs({ className }: { className?: string }) {
  const slider = useSliderContext();

  return slider.value.map((_, index) => (
    <SliderThumb key={index} index={index} className={className} />
  ));
}

const SliderMarkerGroup = forwardRef<
  ComponentRef<typeof SliderPrimitive.MarkerGroup>,
  ComponentProps<typeof SliderPrimitive.MarkerGroup>
>(function SliderMarkerGroup({ className, ...props }, ref) {
  return (
    <SliderPrimitive.MarkerGroup
      ref={ref}
      data-slot="slider-marker-group"
      className={clsx(styles.markerGroup, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderMarker = forwardRef<
  ComponentRef<typeof SliderPrimitive.Marker>,
  ComponentProps<typeof SliderPrimitive.Marker>
>(function SliderMarker({ className, ...props }, ref) {
  return (
    <SliderPrimitive.Marker
      ref={ref}
      data-slot="slider-marker"
      className={clsx(styles.marker, normalizeClassName(className))}
      {...props}
    />
  );
});

const SliderDraggingIndicator = forwardRef<
  ComponentRef<typeof SliderPrimitive.DraggingIndicator>,
  ComponentProps<typeof SliderPrimitive.DraggingIndicator>
>(function SliderDraggingIndicator({ className, ...props }, ref) {
  return (
    <SliderPrimitive.DraggingIndicator
      ref={ref}
      data-slot="slider-dragging-indicator"
      className={clsx(styles.draggingIndicator, normalizeClassName(className))}
      {...props}
    />
  );
});

const Slider = Object.assign(SliderRoot, {
  Root: SliderRoot,
  RootProvider: SliderRootProvider,
  Context: SliderPrimitive.Context,
  useSlider,
  useSliderContext,
  Label: SliderLabel,
  ValueText: SliderValueText,
  Control: SliderControl,
  Track: SliderTrack,
  Range: SliderRange,
  Thumb: SliderThumb,
  Thumbs: SliderThumbs,
  MarkerGroup: SliderMarkerGroup,
  Marker: SliderMarker,
  DraggingIndicator: SliderDraggingIndicator,
});

export { Slider, useSlider, useSliderContext };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    gap: var(--moduix-slider-gap, var(--moduix-spacing-2));
    width: var(--moduix-slider-width, 12rem);
    color: var(--moduix-slider-color, var(--moduix-color-foreground));

    &[data-orientation='vertical'] {
      width: var(--moduix-slider-width-vertical, max-content);
      height: var(--moduix-slider-height, 12rem);
      align-items: center;
    }

    &[data-disabled] {
      opacity: var(--moduix-slider-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .label {
    color: var(
      --moduix-slider-label-color,
      var(--moduix-slider-color, var(--moduix-color-foreground))
    );
    font-size: var(--moduix-slider-label-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-slider-label-font-weight, var(--moduix-weight-regular));
    line-height: var(--moduix-slider-label-line-height, var(--moduix-line-height-text-sm));
    user-select: none;
  }

  .valueText {
    color: var(
      --moduix-slider-value-text-color,
      var(--moduix-slider-color, var(--moduix-color-foreground))
    );
    font-size: var(--moduix-slider-value-text-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-slider-value-text-font-weight, var(--moduix-weight-regular));
    line-height: var(--moduix-slider-value-text-line-height, var(--moduix-line-height-text-sm));
    text-align: right;
  }

  .control {
    position: relative;
    box-sizing: border-box;
    display: flex;
    align-items: center;
    width: 100%;
    min-height: var(--moduix-slider-control-size, var(--moduix-spacing-5));
    touch-action: none;
    user-select: none;
    cursor: pointer;

    &[data-orientation='vertical'] {
      flex-direction: column;
      width: var(--moduix-slider-control-size, var(--moduix-spacing-5));
      height: 100%;
      min-height: 0;
    }

    &[data-disabled] {
      cursor: default;
    }
  }

  .track {
    flex: 1;
    width: 100%;
    height: var(--moduix-slider-track-size, var(--moduix-spacing-1-5));
    overflow: hidden;
    border-radius: var(--moduix-slider-track-radius, var(--moduix-radius-full));
    background-color: var(--moduix-slider-track-bg, var(--moduix-color-muted));
    box-shadow: inset 0 0 0 var(--moduix-slider-track-border-width, var(--moduix-border-width-sm))
      var(--moduix-slider-track-border-color, var(--moduix-color-border));
    user-select: none;

    &[data-orientation='vertical'] {
      width: var(--moduix-slider-track-size, var(--moduix-spacing-1-5));
      height: 100%;
    }
  }

  .range {
    height: 100%;
    border-radius: var(--moduix-slider-range-radius, inherit);
    background-color: var(--moduix-slider-range-bg, var(--moduix-color-primary));

    &[data-orientation='vertical'] {
      width: 100%;
    }
  }

  .thumb {
    box-sizing: border-box;
    display: flex;
    align-items: center;
    justify-content: center;
    width: var(--moduix-slider-thumb-size, var(--moduix-spacing-4));
    height: var(--moduix-slider-thumb-size, var(--moduix-spacing-4));
    border: var(--moduix-slider-thumb-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-slider-thumb-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-slider-thumb-radius, var(--moduix-radius-full));
    background-color: var(--moduix-slider-thumb-bg, var(--moduix-color-background));
    box-shadow: var(--moduix-slider-thumb-shadow, var(--moduix-shadow-sm));
    outline: 0;
    user-select: none;
    transition:
      border-color var(--moduix-slider-transition, var(--moduix-transition-default)),
      background-color var(--moduix-slider-transition, var(--moduix-transition-default)),
      box-shadow var(--moduix-slider-transition, var(--moduix-transition-default));

    &[data-dragging] {
      border-color: var(--moduix-slider-focus-ring-color, var(--moduix-color-ring));
      box-shadow:
        0 0 0 var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
          var(--moduix-slider-focus-ring-color, var(--moduix-color-ring)),
        var(--moduix-slider-thumb-shadow-dragging, var(--moduix-shadow-md));
    }

    &:focus-visible {
      border-color: var(--moduix-slider-focus-ring-color, var(--moduix-color-ring));
      box-shadow: 0 0 0 var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        var(--moduix-slider-focus-ring-color, var(--moduix-color-ring));
    }

    &[data-disabled] {
      pointer-events: none;
    }
  }

  .draggingIndicator {
    top: calc(-1 * var(--moduix-spacing-8));
    padding: var(--moduix-spacing-1) var(--moduix-spacing-2);
    border-radius: var(--moduix-slider-dragging-indicator-radius, var(--moduix-radius-sm));
    background-color: var(--moduix-slider-dragging-indicator-bg, var(--moduix-color-foreground));
    color: var(--moduix-slider-dragging-indicator-color, var(--moduix-color-background));
    font-size: var(--moduix-slider-dragging-indicator-font-size, var(--moduix-text-xs));
    font-weight: var(--moduix-slider-dragging-indicator-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-slider-dragging-indicator-line-height, 1);
    white-space: nowrap;
    pointer-events: none;
  }

  .markerGroup {
    display: flex;
    justify-content: space-between;
    margin-top: var(--moduix-slider-marker-group-margin-top, var(--moduix-spacing-2));

    &[data-orientation='vertical'] {
      flex-direction: column;
      height: 100%;
      margin-top: 0;
      margin-inline-start: var(
        --moduix-slider-marker-group-margin-inline-start,
        var(--moduix-spacing-2)
      );
    }
  }

  .marker {
    position: relative;
    color: var(--moduix-slider-marker-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-slider-marker-font-size, var(--moduix-text-xs));
    line-height: var(--moduix-slider-marker-line-height, var(--moduix-line-height-text-xs));

    &::before {
      position: absolute;
      inset-block-start: calc(-1 * var(--moduix-spacing-2));
      inset-inline-start: 50%;
      width: var(--moduix-slider-marker-dot-size, var(--moduix-spacing-1));
      height: var(--moduix-slider-marker-dot-size, var(--moduix-spacing-1));
      border-radius: var(--moduix-radius-full);
      background-color: var(--moduix-slider-marker-dot-bg, var(--moduix-color-border));
      content: '';
      transform: translateX(-50%);
    }

    &:is([data-state='under-value'], [data-state='at-value'])::before {
      background-color: var(
        --moduix-slider-marker-dot-bg-active,
        var(--moduix-slider-range-bg, var(--moduix-color-primary))
      );
    }
  }
}
